```jac
node MyNode {
    has val:int;
}

walker MyWalker {
    can func1 with MyNode entry {
        ignore [here];
        visit [-->]; # before
        print(here);
    }
}

with entry {
    n1 = MyNode(5);
    n1 ++> MyNode(10) ++> MyNode(15) ++> n1; # will result circular
    n1 spawn MyWalker();
}
```

```jac
node MyNode {
    has val:int;
}

walker MyWalker {
    has Ignore: list = [];

    can func1 with MyNode entry {
        self.Ignore.append(here); # comment here to check the circular graph
        visit [i for i in [-->] if i not in self.Ignore]; # now
        print(here);
    }
}

with entry {
    n1 = MyNode(5);
    n1 ++> MyNode(10) ++> MyNode(15) ++> n1; # will result circular
    n1 spawn MyWalker();
}
```

